import type { JwtPayload } from "jsonwebtoken";
import { prisma } from "../lib/prisma";
import { paymentService } from "../payment/payment.service";

const createRentalRequestIntoDB = async (
  tenantId: string,
  propertyId: string,
) => {
  const property = await prisma.property.findUniqueOrThrow({
    where: {
      id: propertyId,
    },
  });

  if (!property) {
    throw new Error("Property not found.");
  }

  const isExist = await prisma.rentalRequest.findFirst({
    where: {
      tenantId,
      propertyId,
    },
  });

  if (isExist) {
    throw new Error("You have already requested this property.");
  }

  // const totalAmount = Number(property.price)

  const rentalRequest = await prisma.rentalRequest.create({
    data: {
      tenantId,
      propertyId,
    },
  });

  // const paymentUrl = await paymentService.initiatePayment(
  //   rentalRequest.id,
  //   tenantId,
  // );

  return {
    rentalRequest,
    // paymentUrl,
  };
};

const getAllRentalsRequestFromDB = async (tenantId: string) => {
  const result = await prisma.rentalRequest.findMany({
    where: {
      tenantId,
    },
    include: {
      property: true,
    },
    omit: {
      propertyId: true,
    },
  });

  return result;
};

const getSingleRentalsRequestFromDB = async (
  tenantId: string,
  rentalId: string,
) => {
  const result = await prisma.rentalRequest.findFirstOrThrow({
    where: {
      id: rentalId,
      tenantId,
    },

    include: {
      property: true,
    },

    omit: {
      propertyId: true,
    },
  });

  return result;
};

export const rentalRequestService = {
  createRentalRequestIntoDB,
  getAllRentalsRequestFromDB,
  getSingleRentalsRequestFromDB,
};
